import{assign}from"../obj.js";import WebGLPointsLayerRenderer from"../renderer/webgl/PointsLayer.js";import{getSymbolFragmentShader,getSymbolVertexShader,parseSymbolStyle}from"../webgl/ShaderBuilder.js";import Layer from"./Layer.js";class WebGLPointsLayer extends Layer{constructor(e){super(assign({},e)),this.parseResult_=parseSymbolStyle(e.style.symbol)}createRenderer(){return new WebGLPointsLayerRenderer(this,{vertexShader:getSymbolVertexShader(this.parseResult_.params),fragmentShader:getSymbolFragmentShader(this.parseResult_.params),uniforms:this.parseResult_.uniforms,attributes:this.parseResult_.attributes})}}export default WebGLPointsLayer;